using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");

            // BREAKING CHANGE 1 — Discriminator property renamed "$type" in EF9.
            // Existing documents use "Discriminator"; preserve old name so EF9 can
            // read them and direct SQL queries (c.Discriminator) keep working.
            b.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2 — Id synthesis changed in EF9.
            // EF8 stored a shadow "__id" → JSON "id" as "Product|123".
            // EF9 maps the PK directly to JSON "id" as just "123".
            // Restore old layout: keep PK in its own JSON property and use a
            // shadow property with a value generator for the Cosmos resource id.
            b.Property(p => p.Id).ToJsonProperty("Id");
            b.Property<string>("__id")
                .ToJsonProperty("id")
                .HasValueGenerator<LegacyCosmosIdGenerator>();

            // BREAKING CHANGE 3 — HasIndex is not supported by the Cosmos provider.
            // Cosmos indexing is managed at the container level (Azure portal / IaC).
            // Removed: b.HasIndex(p => p.Sku);
        });
    }
}

/// <summary>
/// Generates Cosmos "id" values in the legacy EF Core 8 format: "{EntityType}|{PK}".
/// </summary>
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    public override string Next(EntityEntry entry)
    {
        var entityName = entry.Metadata.ClrType.Name;
        var pk = entry.Property("Id").CurrentValue;
        return $"{entityName}|{pk}";
    }
}

